from vex import ToolVerifier

class VexifiedRetriever:
    def __init__(self, original_tool):
        self.tool = original_tool
        self.verifier = ToolVerifier()

    def retrieve(self, query):
        raw_results = self.tool.retrieve(query)

        verified = self.verifier.check(
            tool_output=raw_results,
            checks=[
                "source_faithfulness",
                "citation_verification",
                "content_validity"
            ]
        )

        if verified.passed:
            return verified.clean_output
        else:
            return {"error": "Retrieval failed verification", "details": verified.errors}

