class VexCrewMonitor:
    def __init__(self, vex_client):
        self.vex = vex_client
        self.turn_count = 0
        self.max_turns = 8

    def pre_execution(self, crew):
        self.crew_state = {"agents_active": len(crew.agents)}

    def post_turn(self, turn_output):
        self.turn_count += 1

        if self.turn_count > self.max_turns:
            raise Exception("Delegation loop detected")

        pipeline_check = self.vex.verify(
            output=turn_output,
            execution_context=self.crew_state,
            checks=[
                "cross_source_consistency",
                "no_task_drift",
                "final_hallucination_check"
            ]
        )

        return pipeline_check.passed

